'use client'
import { useState, useEffect } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { 
  DocumentTextIcon,
  CurrencyDollarIcon,
  ChartBarIcon,
  CalculatorIcon,
  EyeIcon,
  ArrowDownTrayIcon,
  PrinterIcon,
  ClockIcon,
  HashtagIcon,
  UserIcon,
  CubeIcon,
  CheckCircleIcon,
  XCircleIcon
} from '@heroicons/react/24/outline'
import { useAuthStore } from '@/store/useAuthStore'
import { cn } from '@/lib/utils'

interface TransactionItem {
  id: string
  name: string
  quantity: number
  price: number
  costPrice: number
  total: number
  profit: number
}

interface Transaction {
  id: string
  timestamp: string
  cashierId: string
  cashierName: string
  items: TransactionItem[]
  totalAmount: number
  totalProfit: number
  itemCount: number
  status: 'completed' | 'cancelled'
  tenantId: string
  paymentMethod: 'cash' | 'card'
}

// Mock transaction data - in real app, this would come from API
const mockTransactions: Transaction[] = [
  {
    id: 'TXN-001',
    timestamp: new Date().toISOString(),
    cashierId: 'cashier-001',
    cashierName: 'John Smith',
    items: [
      { id: '1', name: 'Coca Cola', quantity: 2, price: 1.50, costPrice: 0.80, total: 3.00, profit: 1.40 },
      { id: '2', name: 'Sandwich', quantity: 1, price: 5.99, costPrice: 3.20, total: 5.99, profit: 2.79 }
    ],
    totalAmount: 8.99,
    totalProfit: 4.19,
    itemCount: 3,
    status: 'completed',
    tenantId: 'branch-a',
    paymentMethod: 'cash'
  },
  {
    id: 'TXN-002',
    timestamp: new Date(Date.now() - 3600000).toISOString(),
    cashierId: 'cashier-002',
    cashierName: 'Sarah Johnson',
    items: [
      { id: '3', name: 'Coffee', quantity: 1, price: 3.50, costPrice: 1.20, total: 3.50, profit: 2.30 },
      { id: '4', name: 'Muffin', quantity: 2, price: 2.99, costPrice: 1.50, total: 5.98, profit: 2.98 }
    ],
    totalAmount: 9.48,
    totalProfit: 5.28,
    itemCount: 3,
    status: 'completed',
    tenantId: 'branch-a',
    paymentMethod: 'card'
  },
  {
    id: 'TXN-003',
    timestamp: new Date(Date.now() - 7200000).toISOString(),
    cashierId: 'cashier-001',
    cashierName: 'John Smith',
    items: [
      { id: '5', name: 'Water Bottle', quantity: 1, price: 1.99, costPrice: 0.90, total: 1.99, profit: 1.09 }
    ],
    totalAmount: 1.99,
    totalProfit: 1.09,
    itemCount: 1,
    status: 'completed',
    tenantId: 'branch-a',
    paymentMethod: 'cash'
  }
]

export default function CheckoutPage() {
  const { user } = useAuthStore()
  const [transactions, setTransactions] = useState<Transaction[]>([])
  const [selectedTransaction, setSelectedTransaction] = useState<Transaction | null>(null)
  const [loading, setLoading] = useState(true)

  // Filter transactions by tenant
  const tenantTransactions = transactions.filter(t => t.tenantId === user?.tenantId)

  // Calculate summary statistics
  const totalTransactions = tenantTransactions.length
  const grossSales = tenantTransactions.reduce((sum, t) => sum + t.totalAmount, 0)
  const netProfit = tenantTransactions.reduce((sum, t) => sum + t.totalProfit, 0)
  const averageOrderValue = totalTransactions > 0 ? grossSales / totalTransactions : 0

  useEffect(() => {
    // Simulate loading
    setTimeout(() => {
      setTransactions(mockTransactions)
      setLoading(false)
    }, 1000)
  }, [])

  const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD'
    }).format(amount)
  }

  const formatTime = (timestamp: string) => {
    return new Date(timestamp).toLocaleTimeString('en-US', {
      hour: '2-digit',
      minute: '2-digit'
    })
  }

  const exportToCSV = () => {
    const headers = ['Transaction ID', 'Time', 'Cashier', 'Items', 'Total', 'Profit', 'Status', 'Payment']
    const rows = tenantTransactions.map(t => [
      t.id,
      formatTime(t.timestamp),
      t.cashierName,
      t.itemCount.toString(),
      formatCurrency(t.totalAmount),
      formatCurrency(t.totalProfit),
      t.status,
      t.paymentMethod
    ])

    const csvContent = [headers, ...rows].map(row => row.join(',')).join('\n')
    const blob = new Blob([csvContent], { type: 'text/csv' })
    const url = URL.createObjectURL(blob)
    const link = document.createElement('a')
    link.href = url
    link.download = `daily-transactions-${new Date().toISOString().split('T')[0]}.csv`
    link.click()
    URL.revokeObjectURL(url)
  }

  const printReport = () => {
    window.print()
  }

  const TransactionDetailModal = ({ transaction, onClose }: { transaction: Transaction; onClose: () => void }) => {
    return (
      <AnimatePresence>
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          className="fixed inset-0 bg-black/40 backdrop-blur-md flex items-center justify-center z-50"
          onClick={onClose}
        >
          <motion.div
            initial={{ scale: 0.9, opacity: 0 }}
            animate={{ scale: 1, opacity: 1 }}
            exit={{ scale: 0.9, opacity: 0 }}
            className="bg-white rounded-xl shadow-xl w-full max-w-2xl mx-4 max-h-[80vh] overflow-hidden"
            onClick={(e) => e.stopPropagation()}
          >
            {/* Modal Header */}
            <div className="flex items-center justify-between p-6 border-b border-gray-200">
              <div>
                <h2 className="text-xl font-semibold text-gray-900">Transaction Details</h2>
                <p className="text-sm text-gray-500">{transaction.id} • {formatTime(transaction.timestamp)}</p>
              </div>
              <button
                onClick={onClose}
                className="p-2 hover:bg-gray-100 rounded-lg transition-colors"
              >
                <XCircleIcon className="w-5 h-5 text-gray-500" />
              </button>
            </div>

            {/* Modal Content */}
            <div className="p-6 overflow-y-auto max-h-[60vh]">
              {/* Transaction Summary */}
              <div className="grid grid-cols-2 gap-4 mb-6">
                <div className="bg-gray-50 p-4 rounded-lg">
                  <p className="text-sm text-gray-500">Cashier</p>
                  <p className="font-semibold">{transaction.cashierName}</p>
                </div>
                <div className="bg-gray-50 p-4 rounded-lg">
                  <p className="text-sm text-gray-500">Payment Method</p>
                  <p className="font-semibold capitalize">{transaction.paymentMethod}</p>
                </div>
                <div className="bg-gray-50 p-4 rounded-lg">
                  <p className="text-sm text-gray-500">Total Amount</p>
                  <p className="font-semibold text-lg">{formatCurrency(transaction.totalAmount)}</p>
                </div>
                <div className="bg-gray-50 p-4 rounded-lg">
                  <p className="text-sm text-gray-500">Status</p>
                  <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${
                    transaction.status === 'completed' 
                      ? 'bg-green-100 text-green-800' 
                      : 'bg-red-100 text-red-800'
                  }`}>
                    {transaction.status}
                  </span>
                </div>
              </div>

              {/* Items List */}
              <div>
                <h3 className="text-lg font-semibold mb-4">Items Sold</h3>
                <div className="space-y-3">
                  {transaction.items.map((item) => (
                    <div key={item.id} className="flex items-center justify-between p-4 bg-gray-50 rounded-lg">
                      <div className="flex-1">
                        <p className="font-medium">{item.name}</p>
                        <p className="text-sm text-gray-500">
                          {item.quantity} × {formatCurrency(item.price)} = {formatCurrency(item.total)}
                        </p>
                      </div>
                      <div className="text-right">
                        <p className="text-sm text-gray-500">Cost: {formatCurrency(item.costPrice)}</p>
                        <p className="text-sm font-medium text-green-600">Profit: {formatCurrency(item.profit)}</p>
                      </div>
                    </div>
                  ))}
                </div>
              </div>

              {/* Profit Summary (Admin only) */}
              {user?.role === 'admin' && (
                <div className="mt-6 p-4 bg-green-50 border border-green-200 rounded-lg">
                  <div className="flex justify-between items-center">
                    <span className="font-medium text-green-800">Total Profit</span>
                    <span className="font-bold text-green-900 text-lg">{formatCurrency(transaction.totalProfit)}</span>
                  </div>
                </div>
              )}
            </div>
          </motion.div>
        </motion.div>
      </AnimatePresence>
    )
  }

  if (loading) {
    return (
      <div className="p-6 space-y-6">
        <h1 className="text-2xl font-bold text-gray-900">Daily Transactions</h1>
        <div className="animate-pulse">
          <div className="h-4 bg-gray-200 rounded w-1/4 mb-4"></div>
          <div className="h-32 bg-gray-200 rounded mb-4"></div>
          <div className="h-64 bg-gray-200 rounded"></div>
        </div>
      </div>
    )
  }

  return (
    <div className="p-6 space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <h1 className="text-2xl font-bold text-gray-900">Daily Transactions</h1>
        <div className="flex gap-3">
          <motion.button
            whileHover={{ scale: 1.02 }}
            whileTap={{ scale: 0.98 }}
            onClick={exportToCSV}
            className="inline-flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
          >
            <ArrowDownTrayIcon className="w-5 h-5" />
            Export CSV
          </motion.button>
          <motion.button
            whileHover={{ scale: 1.02 }}
            whileTap={{ scale: 0.98 }}
            onClick={printReport}
            className="inline-flex items-center gap-2 px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 transition-colors"
          >
            <PrinterIcon className="w-5 h-5" />
            Print Report
          </motion.button>
        </div>
      </div>

      {/* Summary Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {/* Total Transactions */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          className="bg-white/60 backdrop-blur-sm border border-white/20 rounded-xl p-6 shadow-lg"
        >
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm font-medium text-gray-600">Total Transactions</p>
              <p className="text-3xl font-bold text-gray-900">{totalTransactions}</p>
            </div>
            <div className="p-3 bg-blue-100 rounded-full">
              <DocumentTextIcon className="w-6 h-6 text-blue-600" />
            </div>
          </div>
        </motion.div>

        {/* Gross Sales */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.1 }}
          className="bg-white/60 backdrop-blur-sm border border-white/20 rounded-xl p-6 shadow-lg"
        >
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm font-medium text-gray-600">Gross Sales</p>
              <p className="text-3xl font-bold text-gray-900">{formatCurrency(grossSales)}</p>
            </div>
            <div className="p-3 bg-green-100 rounded-full">
              <CurrencyDollarIcon className="w-6 h-6 text-green-600" />
            </div>
          </div>
        </motion.div>

        {/* Net Profit - Admin Only */}
        {user?.role === 'admin' && (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.2 }}
            className="bg-white/60 backdrop-blur-sm border border-white/20 rounded-xl p-6 shadow-lg"
          >
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm font-medium text-gray-600">Net Profit</p>
                <p className="text-3xl font-bold text-green-600">{formatCurrency(netProfit)}</p>
              </div>
              <div className="p-3 bg-green-100 rounded-full">
                <ChartBarIcon className="w-6 h-6 text-green-600" />
              </div>
            </div>
          </motion.div>
        )}

        {/* Average Order Value */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: user?.role === 'admin' ? 0.3 : 0.2 }}
          className="bg-white/60 backdrop-blur-sm border border-white/20 rounded-xl p-6 shadow-lg"
        >
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm font-medium text-gray-600">Avg Order Value</p>
              <p className="text-3xl font-bold text-gray-900">{formatCurrency(averageOrderValue)}</p>
            </div>
            <div className="p-3 bg-purple-100 rounded-full">
              <CalculatorIcon className="w-6 h-6 text-purple-600" />
            </div>
          </div>
        </motion.div>
      </div>

      {/* Transactions Table */}
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 0.4 }}
        className="bg-white/60 backdrop-blur-sm border border-white/20 rounded-xl shadow-lg overflow-hidden"
      >
        <div className="p-6 border-b border-gray-200">
          <h2 className="text-lg font-semibold text-gray-900">Recent Transactions</h2>
          <p className="text-sm text-gray-500 mt-1">Showing {tenantTransactions.length} transactions for {user?.tenantId}</p>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full">
            <thead className="bg-gray-50/50 backdrop-blur-sm">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Time</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Trans ID</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Cashier</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Items Count</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Total</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Status</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Actions</th>
              </tr>
            </thead>
            <tbody className="bg-white/30 divide-y divide-gray-200 backdrop-blur-sm">
              {tenantTransactions.map((transaction) => (
                <motion.tr
                  key={transaction.id}
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  className="hover:bg-white/50 transition-colors cursor-pointer"
                  onClick={() => setSelectedTransaction(transaction)}
                >
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div className="flex items-center">
                      <ClockIcon className="w-4 h-4 text-gray-400 mr-2" />
                      <span className="text-sm text-gray-900">{formatTime(transaction.timestamp)}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div className="flex items-center">
                      <HashtagIcon className="w-4 h-4 text-gray-400 mr-2" />
                      <span className="text-sm font-mono text-gray-900">{transaction.id}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div className="flex items-center">
                      <UserIcon className="w-4 h-4 text-gray-400 mr-2" />
                      <span className="text-sm text-gray-900">{transaction.cashierName}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div className="flex items-center">
                      <CubeIcon className="w-4 h-4 text-gray-400 mr-2" />
                      <span className="text-sm text-gray-900">{transaction.itemCount}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <span className="text-sm font-medium text-gray-900">{formatCurrency(transaction.totalAmount)}</span>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${
                      transaction.status === 'completed'
                        ? 'bg-green-100 text-green-800'
                        : 'bg-red-100 text-red-800'
                    }`}>
                      {transaction.status === 'completed' ? (
                        <CheckCircleIcon className="w-3 h-3 mr-1" />
                      ) : (
                        <XCircleIcon className="w-3 h-3 mr-1" />
                      )}
                      {transaction.status}
                    </span>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <button
                      onClick={(e) => {
                        e.stopPropagation()
                        setSelectedTransaction(transaction)
                      }}
                      className="inline-flex items-center gap-1 px-3 py-1 text-blue-600 hover:bg-blue-50 rounded-lg transition-colors text-sm"
                    >
                      <EyeIcon className="w-4 h-4" />
                      View
                    </button>
                  </td>
                </motion.tr>
              ))}
            </tbody>
          </table>

          {tenantTransactions.length === 0 && (
            <div className="text-center py-12">
              <DocumentTextIcon className="w-12 h-12 text-gray-400 mx-auto mb-4" />
              <h3 className="text-lg font-medium text-gray-900 mb-2">No transactions found</h3>
              <p className="text-gray-500">No transactions available for your branch.</p>
            </div>
          )}
        </div>
      </motion.div>

      {/* Transaction Detail Modal */}
      {selectedTransaction && (
        <TransactionDetailModal 
          transaction={selectedTransaction} 
          onClose={() => setSelectedTransaction(null)} 
        />
      )}
    </div>
  )
}